fn bench_executor_aggregate(c: &mut Criterion) {
    let mut engine = ExecutionEngine::new();
    engine
        .execute(parse("CREATE TABLE orders (id INTEGER, amount INTEGER, category TEXT)").unwrap())
        .unwrap();

    for i in 0..1000 {
        let amount = (i % 100) as i64;
        let category = format!("cat{}", i % 5);
        engine
            .execute(
                parse(&format!(
                    "INSERT INTO orders VALUES ({}, {}, '{}')",
                    i, amount, category
                ))
                .unwrap(),
            )
            .unwrap();
    }

    let mut group = c.benchmark_group("executor_aggregate");

    group.bench_function("count_all", |b| {
        b.iter(|| {
            engine
                .execute(parse("SELECT COUNT(*) FROM orders").unwrap())
                .unwrap()
        });
    });

    group.bench_function("sum_amount", |b| {
        b.iter(|| {
            engine
                .execute(parse("SELECT SUM(amount) FROM orders").unwrap())
                .unwrap()
        });
    });

    group.bench_function("avg_amount", |b| {
        b.iter(|| {
            engine
                .execute(parse("SELECT AVG(amount) FROM orders").unwrap())
                .unwrap()
        });
    });

    group.bench_function("group_by_category", |b| {
        b.iter(|| {
            engine
                .execute(parse("SELECT category, COUNT(*) FROM orders GROUP BY category").unwrap())
                .unwrap()
        });
    });

    group.finish();
}

fn bench_executor_join(c: &mut Criterion) {
    let mut engine = ExecutionEngine::new();
    engine
        .execute(parse("CREATE TABLE users (id INTEGER, name TEXT)").unwrap())
        .unwrap();
    engine
        .execute(parse("CREATE TABLE orders (user_id INTEGER, amount INTEGER)").unwrap())
        .unwrap();

    for i in 0..100 {
        engine
            .execute(parse(&format!("INSERT INTO users VALUES ({}, 'user{}')", i, i)).unwrap())
            .unwrap();
        for j in 0..5 {
            engine
                .execute(parse(&format!("INSERT INTO orders VALUES ({}, {})", i, j * 10)).unwrap())
                .unwrap();
        }
    }

    let mut group = c.benchmark_group("executor_join");

    group.bench_function("inner_join", |b| {
        b.iter(|| {
            engine.execute(
                parse("SELECT users.name, orders.amount FROM users INNER JOIN orders ON users.id = orders.user_id").unwrap()
            )
            .unwrap()
        });
    });

    group.finish();
}

criterion_group!(
    benches,
    bench_executor_select_where,
    bench_executor_insert,
    bench_executor_update,
    bench_executor_delete,
    bench_executor_aggregate,
    bench_executor_join
);
criterion_main!(benches);

use criterion::{criterion_group, criterion_main, BenchmarkId, Criterion};
use sqlrustgo::{parse, ExecutionEngine};

fn bench_end_to_end_select(c: &mut Criterion) {
    let mut engine = ExecutionEngine::new();

    engine
        .execute(
            parse("CREATE TABLE e2e_users (id INTEGER, name TEXT, age INTEGER, email TEXT)")
                .unwrap(),
        )
        .unwrap();

    for i in 0..1000 {
        engine
            .execute(
                parse(&format!(
                    "INSERT INTO e2e_users VALUES ({}, 'user{}', {}, 'user{}@example.com')",
                    i,
                    i,
                    i % 100,
                    i
                ))
                .unwrap(),
            )
            .unwrap();
    }

    let mut group = c.benchmark_group("e2e_select");

    group.bench_function("select_all", |b| {
        b.iter(|| {
            engine
                .execute(parse("SELECT * FROM e2e_users").unwrap())
                .unwrap()
        });
    });

    group.bench_function("select_where", |b| {
        b.iter(|| {
            engine
                .execute(parse("SELECT * FROM e2e_users WHERE age > 50").unwrap())
                .unwrap()
        });
    });

    group.bench_function("select_projection", |b| {
        b.iter(|| {
            engine
                .execute(parse("SELECT name, email FROM e2e_users").unwrap())
                .unwrap()
        });
    });

    group.bench_function("select_order_by", |b| {
        b.iter(|| {
            engine
                .execute(parse("SELECT * FROM e2e_users ORDER BY age DESC").unwrap())
                .unwrap()
        });
    });

    group.bench_function("select_limit", |b| {
        b.iter(|| {
            engine
                .execute(parse("SELECT * FROM e2e_users LIMIT 10").unwrap())
                .unwrap()
        });
    });

    group.finish();
}

fn bench_end_to_end_insert(c: &mut Criterion) {
