fn bench_end_to_end_transaction(c: &mut Criterion) {
    c.bench_function("e2e_transaction", |b| {
        b.iter(|| {
            let mut engine = ExecutionEngine::new();
            engine
                .execute(parse("CREATE TABLE e2e_tx (id INTEGER, value TEXT)").unwrap())
                .unwrap();

            for i in 0..10 {
                engine
                    .execute(
                        parse(&format!("INSERT INTO e2e_tx VALUES ({}, 'tx{}')", i, i)).unwrap(),
                    )
                    .unwrap();
            }

            engine
                .execute(parse("SELECT * FROM e2e_tx").unwrap())
                .unwrap();
            engine
                .execute(parse("UPDATE e2e_tx SET value = 'updated' WHERE id < 5").unwrap())
                .unwrap();
            engine
                .execute(parse("SELECT COUNT(*) FROM e2e_tx").unwrap())
                .unwrap();
        });
    });
}

fn bench_end_to_end_join(c: &mut Criterion) {
    let mut engine = ExecutionEngine::new();
    engine
        .execute(
            parse("CREATE TABLE e2e_orders (id INTEGER, user_id INTEGER, amount INTEGER)").unwrap(),
        )
        .unwrap();
    engine
        .execute(parse("CREATE TABLE e2e_customers (id INTEGER, name TEXT)").unwrap())
        .unwrap();

    for i in 0..500 {
        engine
            .execute(
                parse(&format!(
                    "INSERT INTO e2e_orders VALUES ({}, {}, {})",
                    i,
                    i % 100,
                    i * 10
                ))
                .unwrap(),
            )
            .unwrap();
    }

    for i in 0..100 {
        engine
            .execute(
                parse(&format!(
                    "INSERT INTO e2e_customers VALUES ({}, 'customer{}')",
                    i, i
                ))
                .unwrap(),
            )
            .unwrap();
    }

    c.bench_function("e2e_join", |b| {
        b.iter(|| {
            let _ = engine.execute(parse("SELECT c.name, o.amount FROM e2e_customers c JOIN e2e_orders o ON c.id = o.user_id").unwrap());
        });
    });
}

fn bench_end_to_end_complex(c: &mut Criterion) {
    let mut engine = ExecutionEngine::new();

    engine.execute(parse("CREATE TABLE events (id INTEGER, user_id INTEGER, event_type TEXT, value INTEGER, created_at INTEGER)").unwrap()).unwrap();

    for i in 0..1000 {
        engine
            .execute(
                parse(&format!(
                    "INSERT INTO events VALUES ({}, {}, 'event_type_{}', {}, {})",
                    i,
                    i % 100,
                    i % 5,
                    i * 10,
                    i
                ))
                .unwrap(),
            )
            .unwrap();
    }

    c.bench_function("e2e_complex_query", |b| {
        b.iter(|| {
            engine.execute(
                parse("SELECT user_id, event_type, SUM(value) as total FROM events WHERE created_at > 100 AND event_type IN ('event_type_0', 'event_type_2') GROUP BY user_id, event_type HAVING total > 1000 ORDER BY total DESC LIMIT 50")
                    .unwrap()
            ).unwrap()
        });
    });
}

criterion_group!(
    benches,
    bench_end_to_end_select,
    bench_end_to_end_insert,
    bench_end_to_end_update,
    bench_end_to_end_transaction,
    bench_end_to_end_join,
    bench_end_to_end_complex
);
criterion_main!(benches);

//! Lexer Benchmark Tests
//!
//! Benchmarks for SQL tokenization performance.

use criterion::{criterion_group, criterion_main, Criterion};
use sqlrustgo::lexer::tokenize;

// Simple SQL queries for benchmarking
const SQL_SIMPLE: &str = "SELECT id FROM users WHERE id = 1";
const SQL_MEDIUM: &str = "SELECT id, name, email, age FROM users WHERE status = 'active'";
const SQL_COMPLEX: &str = "SELECT u.id, u.name, o.amount, o.status FROM users u JOIN orders o ON u.id = o.user_id WHERE u.age > 18 AND o.amount > 100";
const SQL_INSERT: &str = "INSERT INTO users (id, name, email, age, status) VALUES (1, 'Alice', 'alice@example.com', 25, 'active')";
const SQL_UPDATE: &str = "UPDATE users SET name = 'Bob', email = 'bob@example.com' WHERE id = 1";
const SQL_DELETE: &str = "DELETE FROM users WHERE id = 1 AND status = 'inactive'";
const SQL_CREATE: &str =
    "CREATE TABLE users (id INTEGER PRIMARY KEY, name TEXT, email TEXT, age INTEGER)";
const SQL_DROP: &str = "DROP TABLE users";
const SQL_AGGREGATE: &str = "SELECT COUNT(*), SUM(amount), AVG(price), MIN(id), MAX(name) FROM orders WHERE status = 'active'";
const SQL_MULTI_LINE: &str = "
    SELECT
        id,
        name,
        email,
        age,
        status,
        created_at,
        updated_at
    FROM
        users
    WHERE
        status = 'active'
        AND age >= 18
        AND age <= 65
    ORDER BY
        created_at DESC
    LIMIT 100
    OFFSET 50
";

fn bench_lexer_simple(c: &mut Criterion) {
    c.bench_function("lexer_simple_select", |b| {
        b.iter(|| tokenize(SQL_SIMPLE));
    });
}

fn bench_lexer_medium(c: &mut Criterion) {
    c.bench_function("lexer_medium_select", |b| {
        b.iter(|| tokenize(SQL_MEDIUM));
    });
}

fn bench_lexer_complex(c: &mut Criterion) {
    c.bench_function("lexer_complex_join", |b| {
        b.iter(|| tokenize(SQL_COMPLEX));
    });
}

fn bench_lexer_insert(c: &mut Criterion) {
