    bench_lexer_medium,
    bench_lexer_complex,
    bench_lexer_insert,
    bench_lexer_update,
    bench_lexer_delete,
    bench_lexer_create_table,
    bench_lexer_drop_table,
    bench_lexer_aggregate,
    bench_lexer_multi_line,
    bench_lexer_empty,
    bench_lexer_whitespace_only,
    bench_lexer_single_keyword,
    bench_lexer_batch_simple
);
criterion_main!(benches);

