fn bench_lexer_long(c: &mut Criterion) {
    let mut sql = String::from("SELECT ");
    for i in 0..50 {
        sql.push_str(&format!("user_{}, ", i));
    }
    sql.push_str("created_at FROM users WHERE ");
    for i in 0..20 {
        sql.push_str(&format!("col{} = {} AND ", i, i));
    }
    sql.pop();
    sql.pop();
    sql.pop();

    c.bench_function("lexer_long", |b| {
        b.iter(|| tokenize(&sql));
    });
}

